# JSON serializer/deserializer for Memcached
def json_serializer(key, value):
    if isinstance(value, str):
        return value, 1
    return json.dumps(value), 2


def json_deserializer(key, value, flags):
    if flags == 1:
        return value.decode('utf-8')
    if flags == 2:
        return json.loads(value.decode('utf-8'))
    raise Exception("Unknown serialization format")


# Initialize Memcached client with retry logic
def get_memcached_client():
    base_client = Client(
        (app.config['MEMCACHED_HOST'], app.config['MEMCACHED_PORT']),
        serializer=json_serializer,
        deserializer=json_deserializer,
        connect_timeout=5,
        timeout=3,
        no_delay=True,
        max_pool_size=10
    )
    client = RetryingClient(
        base_client,
        attempts=3,
        retry_delay=0.1,
        retry_for=[MemcacheUnexpectedCloseError, ConnectionRefusedError, OSError]
    )
    return client


cache_client = get_memcached_client()


# Cache helper class
class CacheManager:
    def __init__(self, client):
        self.client = client

    def get(self, key):
        try:
            return self.client.get(key)
        except Exception as e:
            app.logger.error(f"Cache GET error for key '{key}': {e}")
            return None

    def set(self, key, value, ttl=None):
        if ttl is None:
            ttl = app.config['DEFAULT_CACHE_TTL']
        try:
            self.client.set(key, value, expire=ttl)
            return True
        except Exception as e:
            app.logger.error(f"Cache SET error for key '{key}': {e}")
            return False

    def delete(self, key):
        try:
            self.client.delete(key)
            return True
        except Exception as e:
            app.logger.error(f"Cache DELETE error for key '{key}': {e}")
            return False

    def flush_all(self):
        try:
            self.client.flush_all()
            return True
        except Exception as e:
            app.logger.error(f"Cache FLUSH error: {e}")
            return False

    def get_stats(self):
        try:
            return self.client.stats()
        except Exception as e:
            app.logger.error(f"Cache STATS error: {e}")
            return None

    def generate_key(self, prefix, *args, **kwargs):
        key_data = f"{prefix}:{json.dumps(args, sort_keys=True)}:{json.dumps(kwargs, sort_keys=True)}"
        return hashlib.md5(key_data.encode()).hexdigest()


cache_manager = CacheManager(cache_client)


