# Simulated slow database queries
def simulate_db_query(table, record_id=None, filters=None, delay=0.5):
    """Simulate a slow database query with optional delay."""
    time.sleep(delay)  # Simulate database latency
    
    if table not in FAKE_DATABASE:
        return None
    
    data = FAKE_DATABASE[table]
    
    if record_id:
        return data.get(record_id)
    
    results = list(data.values())
    
    if filters:
        for key, value in filters.items():
            results = [r for r in results if r.get(key) == value]
    
    return results


# Decorator for caching function results
def cached(prefix, ttl=None):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = cache_manager.generate_key(prefix, *args, **kwargs)
            
            # Try to get from cache
            cached_result = cache_manager.get(cache_key)
            if cached_result is not None:
                app.logger.info(f"Cache HIT for {prefix} - key: {cache_key}")
                if isinstance(cached_result, dict):
                    cached_result['_cache'] = 'hit'
                return cached_result
            
            # Cache miss - execute function
            app.logger.info(f"Cache MISS for {prefix} - key: {cache_key}")
            result = func(*args, **kwargs)
            
            if result is not None:
                effective_ttl = ttl or app.config['DEFAULT_CACHE_TTL']
                cache_manager.set(cache_key, result, effective_ttl)
            
            if isinstance(result, dict):
                result['_cache'] = 'miss'
            
            return result
        
        return wrapper
    return decorator


# Decorator for caching API route responses
def cache_response(ttl=None, key_prefix=None):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Generate cache key from request URL and query parameters
            cache_key_data = f"{key_prefix or func.__name__}:{request.url}:{json.dumps(dict(request.args), sort_keys=True)}"
            cache_key = hashlib.md5(cache_key_data.encode()).hexdigest()
            
            # Try to get from cache
            cached_result = cache_manager.get(cache_key)
            if cached_result is not None:
                app.logger.info(f"API Cache HIT for {request.url}")
                cached_result['_cache_info'] = {
                    'status': 'hit',
                    'key': cache_key
                }
                return jsonify(cached_result)
            
            # Cache miss
            app.logger.info(f"API Cache MISS for {request.url}")
            result = func(*args, **kwargs)
            
            # Cache the response data
            if result is not None:
                response_data = result.get_json() if hasattr(result, 'get_json') else result
                effective_ttl = ttl or app.config['API_CACHE_TTL']
                cache_manager.set(cache_key, response_data, effective_ttl)
                
                if isinstance(response_data, dict):
                    response_data['_cache_info'] = {
                        'status': 'miss',
                        'key': cache_key,
                        'ttl': effective_ttl
                    }
                    return jsonify(response_data)
            
            return result
        
        return wrapper
    return decorator


