# Aggregated data endpoint with multiple cached queries
@app.route('/api/dashboard')
@cache_response(ttl=60, key_prefix="api_dashboard")
def dashboard():
    start_time = time.time()
    
    users = get_all_users_from_db()
    products = get_all_products_from_db()
    
    # Calculate some statistics
    total_stock = sum(p.get('stock', 0) for p in products.get('data', []))
    total_inventory_value = sum(
        p.get('price', 0) * p.get('stock', 0) for p in products.get('data', [])
    )
    
    categories = {}
    for p in products.get('data', []):
        cat = p.get('category', 'unknown')
        if cat not in categories:
            categories[cat] = 0
        categories[cat] += 1
    
    elapsed = time.time() - start_time
    
    result = {
        "summary": {
            "total_users": users.get('count', 0),
            "total_products": products.get('count', 0),
            "total_stock": total_stock,
            "total_inventory_value": round(total_inventory_value, 2),
            "product_categories": categories,
        },
        "response_time_ms": round(elapsed * 1000, 2),
        "timestamp": time.time()
    }
    return jsonify(result)


# Cache management endpoints
@app.route('/api/cache/stats')
def cache_stats():
    stats = cache_manager.get_stats()
    if stats:
        # Convert bytes keys/values to strings for JSON serialization
        formatted_stats = {}
        for key, value in stats.items():
            str_key = key.decode('utf-8') if isinstance(key, bytes) else str(key)
            if isinstance(value, bytes):
                str_value = value.decode('utf-8')
            else:
                str_value = value
            formatted_stats[str_key] = str_value
        
        return jsonify({
            "status": "ok",
            "stats": formatted_stats
        })
    return jsonify({"status": "error", "message": "Could not retrieve cache stats"}), 500


