# Manual cache set/get for testing
@app.route('/api/cache/set', methods=['POST'])
def set_cache():
    data = request.get_json()
    if not data or 'key' not in data or 'value' not in data:
        return jsonify({"error": "Must provide 'key' and 'value' in JSON body"}), 400
    
    key = data['key']
    value = data['value']
    ttl = data.get('ttl', app.config['DEFAULT_CACHE_TTL'])
    
    success = cache_manager.set(key, value, ttl)
    if success:
        return jsonify({"status": "ok", "key": key, "ttl": ttl})
    return jsonify({"status": "error", "message": "Failed to set cache"}), 500


@app.route('/api/cache/get/<key>')
def get_cache(key):
    value = cache_manager.get(key)
    if value is not None:
        return jsonify({"status": "ok", "key": key, "value": value})
    return jsonify({"status": "ok", "key": key, "value": None, "message": "Key not found or expired"})


