@app.route('/api/benchmark/cached')
def benchmark_cached():
    """Benchmark endpoint with caching - subsequent calls should be fast."""
    iterations = int(request.args.get('iterations', 5))
    results = []
    
    for i in range(iterations):
        start = time.time()
        get_user_from_db("1")
        get_product_from_db("101")
        get_all_users_from_db()
        elapsed = time.time() - start
        results.append(round(elapsed * 1000, 2))
    
    return jsonify({
        "type": "cached",
        "iterations": iterations,
        "times_ms": results,
        "avg_ms": round(sum(results) / len(results), 2),
        "min_ms": min(results),
        "max_ms": max(results),
        "total_ms": round(sum(results), 2)
    })


