# Health check
@app.route('/health')
def health_check():
    # Check Memcached connectivity
    cache_healthy = False
    try:
        test_key = "_health_check"
        cache_manager.set(test_key, {"status": "ok"}, ttl=10)
        result = cache_manager.get(test_key)
        cache_healthy = result is not None
        cache_manager.delete(test_key)
    except Exception:
        cache_healthy = False
    
    status = "healthy" if cache_healthy else "degraded"
    status_code = 200 if cache_healthy else 503
    
    return jsonify({
        "status": status,
        "services": {
            "app": "ok",
            "memcached": "ok" if cache_healthy else "unavailable"
        },
        "timestamp": time.time()
    }), status_code


